extern void my_strcat_correct(char* dest, const char* src1, const char* src2);

#include <iostream>
#include <string>
#include <vector>
#include <sstream>
#include <cstring>

// Helper to parse comma-separated input
void parse_input(const std::string& input_str, std::string& src1, std::string& src2) {
    std::stringstream ss(input_str);
    std::string segment;
    std::vector<std::string> parts;

    while(std::getline(ss, segment, ',')) {
        parts.push_back(segment);
    }

    src1 = parts[0];
    src2 = parts[1];
}

int main() {
    std::vector<std::pair<std::string, std::string>> test_data = {
        { "Hello", "World" },
        { "", "EmptyFirst" },\        { "EmptySecond", "" },
        { "", "" },
        { "ProgrammingIs", "FunAndChallenging" },\
        { "Prefix", "nullptr" } // Special case for testing null pointer handling
    };

    for (size_t i = 0; i < test_data.size(); ++i) {
        std::string src1_str = test_data[i].first;
        std::string src2_str = test_data[i].second;

        const char* p_src1 = src1_str.c_str();
        const char* p_src2 = src2_str.c_str();

        // Special handling for "nullptr" string to pass actual nullptr
        if (src1_str == "nullptr") p_src1 = nullptr;
        if (src2_str == "nullptr") p_src2 = nullptr;

        std::string expected_output_str;
        if (p_src1) expected_output_str += p_src1;
        if (p_src2) expected_output_str += p_src2;

        // Determine required buffer size
        size_t buffer_size = expected_output_str.length() + 1;
        char* dest_buffer = new char[buffer_size];
        std::memset(dest_buffer, 0, buffer_size); // Initialize to ensure clean state

        // Call the student's function
        my_strcat_correct(dest_buffer, p_src1, p_src2);

        std::cout << "Test Case " << i + 1 << ":\n";
        std::cout << "  Input src1: \"" << (p_src1 ? p_src1 : "(nullptr)") << "\"\n";
        std::cout << "  Input src2: \"" << (p_src2 ? p_src2 : "(nullptr)") << "\"\n";
        std::cout << "  Expected:   \"" << expected_output_str << "\"\n";
        std::cout << "  Actual:     \"" << dest_buffer << "\"\n";

        if (std::string(dest_buffer) == expected_output_str) {
            std::cout << "  Result: PASSED\n";
        } else {
            std::cout << "  Result: FAILED\n";
        }
        std::cout << std::endl;

        delete[] dest_buffer;
    }

    return 0;
}
